package com.jdmedia.controller;
import com.jdmedia.model.ConversionSummary;import com.jdmedia.service.AppContext;import javafx.fxml.FXML;import javafx.scene.control.*;import java.awt.Desktop;import java.io.IOException;import java.nio.file.Path;
public final class ResultController {private final AppContext context;@FXML private Label resultLabel;@FXML private Button folderButton;public ResultController(AppContext context){this.context=context;}@FXML public void initialize(){ConversionSummary s=context.conversion().lastSummary();folderButton.setDisable(context.conversion().lastOutputDirectory()==null);if(s==null){resultLabel.setText("No hay estadísticas disponibles.");return;}long saved=s.originalBytes()-s.finalBytes();double percent=s.originalBytes()==0?0:(saved*100.0/s.originalBytes());resultLabel.setText("Archivos completados: "+s.completedFiles()+" de "+s.totalFiles()+"\nTamaño original: "+size(s.originalBytes())+"  →  final: "+size(s.finalBytes())+"\nEspacio ahorrado: "+size(saved)+" ("+String.format("%.1f",percent)+"%)\nTiempo empleado: "+time(s.elapsedSeconds())+(s.cancelled()?"\nProceso cancelado.":""));}@FXML private void openFolder(){open(context.conversion().lastOutputDirectory());}@FXML private void home(){context.navigation().show("home-view.fxml");}@FXML private void history(){context.navigation().show("history-view.fxml");}private void open(Path path){try{Desktop.getDesktop().open(path.toFile());}catch(IOException e){context.status().error("No se pudo abrir la ubicación: "+e.getMessage());}}private String size(long b){return String.format("%.2f GB",b/1_073_741_824d);}private String time(long seconds){return String.format("%d min %02d s",seconds/60,seconds%60);}}
